from pydantic import BaseModel, Field
from typing import Literal
from functools import wraps

class ToolRegistry:
    """企业工具注册中心"""
    _tools = {}

    @classmethod
    def register(cls, name: str, description: str, risk_level: str = "low"):
        """注册工具装饰器"""
        def decorator(func):
            cls._tools[name] = {
                "func": func,
                "description": description,
                "risk_level": risk_level,
                "params_model": func.__annotations__.get('params', BaseModel)
            }
            return func
        return decorator

@ToolRegistry.register("query_employee", "查询员工信息（HR系统）", risk_level="low")
class EmployeeQuery(BaseModel):
    employee_id: str = Field(..., description="员工工号")

class EmployeeResult(BaseModel):
    name: str
    department: str
    email: str

